from src.nodes.base import BaseNode

async def execute(self, inputs):
    text = inputs.get('text') or self.get_parameter('text', '')
    sep = inputs.get('separator') if inputs.get('separator') is not None else self.get_parameter('separator', '')
    try:
        if sep:
            items = str(text).split(sep)
        else:
            items = str(text).split()
    except Exception as e:
        self.log_info(f'Split error: {e}')
        items = []

    await self.set_output('items', items)
    await self.set_output('exec_out', True)
    return {'items': items}
